<template><view class="page"><view class="card" v-for="a in items" :key="a.id" @click="go(a.id)"><text class="title">{{a.title}}</text><text class="muted">{{a.createdAt}}</text></view><view v-if="!items.length" class="card muted">暂无公告</view></view></template><script setup lang="ts">import { ref } from 'vue';import { onShow } from '@dcloudio/uni-app';import { contentApi } from '@/services/content';const items=ref<any[]>([]);function go(id:any){uni.navigateTo({url:'/pages/announcement/detail/index?id='+id})}onShow(async()=>items.value=(await contentApi.announcements()).data||[])</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.title{display:block;font-size:34rpx;font-weight:900}.muted{display:block;color:#8d8175;font-size:24rpx;margin-top:12rpx}</style>
